WITH params AS (SELECT (timezone('Asia/Ho_Chi_Minh', now()))::date AS today_vn, ((timezone('Asia/Ho_Chi_Minh', now()))::date - 30) AS lookback30), product_counts AS (SELECT count(*)::numeric AS live_products FROM public.products WHERE deleted_at IS NULL), opening_counts AS (SELECT count(*)::numeric AS live_openings, count(DISTINCT period_month::date)::numeric AS distinct_opening_dates FROM public.inventory_opening_balances WHERE deleted_at IS NULL AND period_month::date <= (SELECT today_vn FROM params)), tx_counts AS (SELECT count(*)::numeric AS linked_adjustments_90d FROM public.inventory_transactions WHERE deleted_at IS NULL AND tx_type IN ('adjust_in','adjust_out') AND adjusted_from_transaction_id IS NOT NULL AND tx_date::date >= (SELECT today_vn - 90 FROM params)) SELECT 'A_counts' AS section, 'live_products' AS metric, live_products AS value FROM product_counts UNION ALL SELECT 'A_counts','live_openings_until_today',live_openings FROM opening_counts UNION ALL SELECT 'A_counts','distinct_opening_dates_until_today',distinct_opening_dates FROM opening_counts UNION ALL SELECT 'A_counts','linked_adjustments_last_90_days',linked_adjustments_90d FROM tx_counts;
WITH params AS (SELECT (timezone('Asia/Ho_Chi_Minh', now()))::date AS today_vn, ((timezone('Asia/Ho_Chi_Minh', now()))::date - 30) AS lookback30), open_dates AS (SELECT period_month::date AS d, bool_and(source_stocktake_id IS NOT NULL) AS is_end_of_day_snapshot FROM public.inventory_opening_balances, params WHERE deleted_at IS NULL AND period_month::date <= params.today_vn GROUP BY period_month::date), selected_bound AS (SELECT COALESCE((SELECT d FROM open_dates ORDER BY d DESC LIMIT 1), (SELECT lookback30 FROM params)) AS baseline_date, COALESCE((SELECT CASE WHEN is_end_of_day_snapshot THEN d + 1 ELSE d END FROM open_dates ORDER BY d DESC LIMIT 1), (SELECT lookback30 FROM params)) AS effective_start FROM params), rpc_rows AS (SELECT r.* FROM selected_bound b, params p CROSS JOIN LATERAL public.inventory_calculate_product_stock_v1(b.baseline_date::text, b.effective_start::text, (p.today_vn + 1)::text) r), products_all AS (SELECT id, sku, name, unit_price FROM public.products WHERE deleted_at IS NULL), products_limited AS (SELECT id, sku, name, unit_price FROM public.products WHERE deleted_at IS NULL ORDER BY id LIMIT 1000), totals AS (SELECT b.baseline_date, b.effective_start, count(r.product_id)::numeric AS rpc_product_rows, COALESCE(sum(r.current_qty),0)::numeric AS total_qty, COALESCE(sum(r.current_qty * COALESCE(pa.unit_price,0)),0)::numeric AS total_value_all_products, COALESCE(sum(r.current_qty * COALESCE(pl.unit_price,0)),0)::numeric AS total_value_first_1000_products_by_id, COALESCE(sum(CASE WHEN pl.id IS NULL THEN r.current_qty * COALESCE(pa.unit_price,0) ELSE 0 END),0)::numeric AS value_missing_if_products_capped FROM rpc_rows r CROSS JOIN selected_bound b LEFT JOIN products_all pa ON pa.id = r.product_id LEFT JOIN products_limited pl ON pl.id = r.product_id GROUP BY b.baseline_date, b.effective_start) SELECT 'B_total_value_check' AS section, baseline_date, effective_start, rpc_product_rows, total_qty, total_value_all_products, total_value_first_1000_products_by_id, value_missing_if_products_capped FROM totals;
WITH params AS (SELECT (timezone('Asia/Ho_Chi_Minh', now()))::date AS today_vn, ((timezone('Asia/Ho_Chi_Minh', now()))::date - 30) AS lookback30), open_dates AS (SELECT period_month::date AS d, bool_and(source_stocktake_id IS NOT NULL) AS is_end_of_day_snapshot FROM public.inventory_opening_balances, params WHERE deleted_at IS NULL AND period_month::date <= params.today_vn GROUP BY period_month::date), selected_bound AS (SELECT COALESCE((SELECT d FROM open_dates ORDER BY d DESC LIMIT 1), (SELECT lookback30 FROM params)) AS baseline_date, COALESCE((SELECT CASE WHEN is_end_of_day_snapshot THEN d + 1 ELSE d END FROM open_dates ORDER BY d DESC LIMIT 1), (SELECT lookback30 FROM params)) AS effective_start FROM params), rpc_rows AS (SELECT r.* FROM selected_bound b, params p CROSS JOIN LATERAL public.inventory_calculate_product_stock_v1(b.baseline_date::text, b.effective_start::text, (p.today_vn + 1)::text) r), products_all AS (SELECT id, sku, name, unit_price FROM public.products WHERE deleted_at IS NULL), products_limited AS (SELECT id FROM public.products WHERE deleted_at IS NULL ORDER BY id LIMIT 1000) SELECT 'C_top_value_rows_missing_if_product_fetch_capped' AS section, pa.sku, pa.name, r.current_qty, COALESCE(pa.unit_price,0) AS unit_price, (r.current_qty * COALESCE(pa.unit_price,0)) AS inventory_value FROM rpc_rows r JOIN products_all pa ON pa.id = r.product_id LEFT JOIN products_limited pl ON pl.id = r.product_id WHERE pl.id IS NULL AND (r.current_qty * COALESCE(pa.unit_price,0)) <> 0 ORDER BY abs(r.current_qty * COALESCE(pa.unit_price,0)) DESC LIMIT 50;
WITH params AS (SELECT (timezone('Asia/Ho_Chi_Minh', now()))::date AS today_vn), adjustments AS (SELECT t.id, t.product_id, t.tx_date::date AS adjustment_date, t.tx_type AS adjustment_type, t.qty, o.tx_type AS original_type, public.inventory_signed_effect(t.tx_type, t.qty, o.tx_type) AS signed_stock_effect FROM public.inventory_transactions t LEFT JOIN public.inventory_transactions o ON o.id = t.adjusted_from_transaction_id AND o.deleted_at IS NULL, params p WHERE t.deleted_at IS NULL AND t.tx_type IN ('adjust_in','adjust_out') AND t.adjusted_from_transaction_id IS NOT NULL AND t.tx_date::date >= p.today_vn - 90) SELECT 'D_adjustment_sign_check_90d' AS section, adjustment_type, original_type, count(*) AS row_count, COALESCE(sum(qty),0) AS raw_qty_sum, COALESCE(sum(signed_stock_effect),0) AS signed_stock_effect_sum FROM adjustments GROUP BY adjustment_type, original_type ORDER BY original_type, adjustment_type;
WITH params AS (SELECT (timezone('Asia/Ho_Chi_Minh', now()))::date AS today_vn, ((timezone('Asia/Ho_Chi_Minh', now()))::date - 30) AS lookback30), open_dates AS (SELECT period_month::date AS d, bool_and(source_stocktake_id IS NOT NULL) AS is_end_of_day_snapshot FROM public.inventory_opening_balances, params WHERE deleted_at IS NULL AND period_month::date <= params.today_vn GROUP BY period_month::date), correct_bound AS (SELECT COALESCE((SELECT d FROM open_dates ORDER BY d DESC LIMIT 1), (SELECT lookback30 FROM params)) AS baseline_date, COALESCE((SELECT CASE WHEN is_end_of_day_snapshot THEN d + 1 ELSE d END FROM open_dates ORDER BY d DESC LIMIT 1), (SELECT lookback30 FROM params)) AS effective_start FROM params), correct_total AS (SELECT COALESCE(sum(r.current_qty * COALESCE(p.unit_price,0)),0)::numeric AS value FROM correct_bound b, params prm CROSS JOIN LATERAL public.inventory_calculate_product_stock_v1(b.baseline_date::text, b.effective_start::text, (prm.today_vn + 1)::text) r LEFT JOIN public.products p ON p.id = r.product_id AND p.deleted_at IS NULL), candidate_dates AS (SELECT d, CASE WHEN is_end_of_day_snapshot THEN d + 1 ELSE d END AS effective_start FROM open_dates ORDER BY d DESC LIMIT 20), candidate_totals AS (SELECT c.d AS candidate_baseline_date, c.effective_start, COALESCE(sum(r.current_qty * COALESCE(p.unit_price,0)),0)::numeric AS candidate_total_value FROM candidate_dates c, params prm CROSS JOIN LATERAL public.inventory_calculate_product_stock_v1(c.d::text, c.effective_start::text, (prm.today_vn + 1)::text) r LEFT JOIN public.products p ON p.id = r.product_id AND p.deleted_at IS NULL GROUP BY c.d, c.effective_start) SELECT 'E_possible_dashboard_opening_bound_impact' AS section, candidate_baseline_date, effective_start, candidate_total_value, (candidate_total_value - (SELECT value FROM correct_total)) AS diff_vs_correct_total FROM candidate_totals ORDER BY abs(candidate_total_value - (SELECT value FROM correct_total)) DESC LIMIT 20;
